import { LlamaCloud } from '@llamaindex/llama-cloud';
import fs from 'fs';

async function main() {
  const client = new LlamaCloud();

  // Read the job ID from the log file
  const logContent = fs.readFileSync('/home/user/parse-task/output/result.log', 'utf-8');
  const jobMatch = logContent.match(/Job ID: (.+)/);

  if (!jobMatch) {
    console.error('Could not find Job ID in log file');
    process.exit(1);
  }

  const jobId = jobMatch[1].trim();
  console.log(`Verifying job: ${jobId}`);

  // Retrieve the job details
  const job = await client.parsing.get(jobId);

  console.log('Job details:');
  console.log(`  ID: ${job.id}`);
  console.log(`  Status: ${job.status}`);
  console.log(`  Tier: ${job.tier}`);
  console.log(`  Version: ${job.version}`);

  if (job.tier === 'cost_effective') {
    console.log('\n✓ Job tier is correctly set to cost_effective');
    process.exit(0);
  } else {
    console.error(`\n✗ Job tier is ${job.tier}, expected cost_effective`);
    process.exit(1);
  }
}

main().catch((error) => {
  console.error('Error:', error);
  process.exit(1);
});

